        expiresAt = null,
        quantity = 1,
        totalPrice = 10.0,
        createdAt = 0L,
    )

    private val fakeOrderDao = object : OrderDao {
        override suspend fun upsert(order: OrderEntity) = Unit
        override suspend fun update(order: OrderEntity) = Unit
        override suspend fun getById(orderId: String): OrderEntity? =
            if (orderId == "ord-1") testOrder else null
        override suspend fun getByIdForActor(orderId: String, actorId: String): OrderEntity? =
            if (orderId == "ord-1" && actorId == "operator") testOrder else null
        override suspend fun getByIdForOwnerOrDelegate(orderId: String, ownerId: String, delegateOwnerId: String): OrderEntity? =
            if (orderId == "ord-1" && (ownerId == "operator" || delegateOwnerId == "operator")) testOrder else null
        override fun observeById(orderId: String): Flow<OrderEntity?> = emptyFlow()
        override suspend fun getActiveByResource(resourceId: String) = emptyList<OrderEntity>()
        override suspend fun deleteById(orderId: String) = Unit
        override suspend fun page(limit: Int) = emptyList<OrderEntity>()
        override suspend fun getExpiredPendingOrders(nowMillis: Long) = emptyList<OrderEntity>()
        override suspend fun sumGrossByDateRange(fromMillis: Long, toMillis: Long) = 0.0
        override suspend fun sumRefundsByDateRange(fromMillis: Long, toMillis: Long) = 0.0
    }

    private val fakeResourceDao = object : ResourceDao {
        override suspend fun upsert(resource: ResourceEntity) = Unit
        override suspend fun upsertAll(resources: List<ResourceEntity>) = Unit
        override suspend fun update(resource: ResourceEntity) = Unit
        override suspend fun getById(id: String): ResourceEntity? = null
        override suspend fun page(limit: Int, offset: Int) = emptyList<ResourceEntity>()
        override suspend fun countAll() = 0
        override suspend fun deleteById(id: String) = Unit
    }

    private fun createVm(): OrderWorkflowViewModel {
        return OrderWorkflowViewModel(
            orderDao = fakeOrderDao,
            resourceDao = fakeResourceDao,
            stateMachine = object : OrderStateMachine(
                database = throw UnsupportedOperationException(),
                clock = testClock,
            ) {
                override suspend fun <R> runInTransaction(block: suspend () -> R): R = block()
            },
            bookingUseCase = BookingUseCase(fakeOrderDao, testClock),
            permissionEvaluator = PermissionEvaluator(defaultRules()),
            validationService = ValidationService(testClock),
            clock = testClock,
        )
    }

    @Test
    fun `owner can load own order`() = runTest {
        val vm = createVm()
        vm.loadOrderById("ord-1", Role.Operator, "operator")
        // Allow async to settle
        kotlinx.coroutines.delay(100)
        assertEquals("ord-1", vm.state.value.lastOrderId)
        assertEquals("Confirmed", vm.state.value.lastOrderState)
    }

    @Test
    fun `unauthorized user cannot load another users order`() = runTest {
        val vm = createVm()
        vm.loadOrderById("ord-1", Role.Operator, "other-user")
        kotlinx.coroutines.delay(100)
        assertEquals("Order not found or access denied", vm.state.value.error)
    }

    @Test
    fun `admin can load any order`() = runTest {
        val vm = createVm()
        vm.loadOrderById("ord-1", Role.Admin, "admin-user")
        kotlinx.coroutines.delay(100)
        assertEquals("ord-1", vm.state.value.lastOrderId)
        assertEquals("Confirmed", vm.state.value.lastOrderState)
    }

    @Test
    fun `supervisor can load any order`() = runTest {
        val vm = createVm()
        vm.loadOrderById("ord-1", Role.Supervisor, "supervisor-user")
        kotlinx.coroutines.delay(100)
        assertEquals("ord-1", vm.state.value.lastOrderId)
    }

    @Test
    fun `delegate can load delegated users order`() = runTest {
        val vm = createVm()
        vm.loadOrderById("ord-1", Role.Companion, "companion-user", "operator")
        kotlinx.coroutines.delay(100)
        assertEquals("ord-1", vm.state.value.lastOrderId)
    }

    @Test
    fun `no unrestricted loadOrderById method available`() {
        // Verify the unrestricted single-param loadOrderById is removed
        // The only loadOrderById signature requires role, actorId parameters
        val vm = createVm()
        // This test documents that the only public loadOrderById requires authorization params
        val methods = vm::class.members.filter { it.name == "loadOrderById" }
        // All loadOrderById methods should require at least role and actorId
        methods.forEach { method ->
            assert(method.parameters.size >= 3) {
                "loadOrderById should require role and actorId parameters but found ${method.parameters.size} params"
            }
        }
    }
}
