    fun `admin can access admin screen`() {
        assertTrue(AppNavigator.isScreenAllowed(Screen.Admin, Role.Admin))
    }

    @Test
    fun `supervisor cannot access admin screen`() {
        assertFalse(AppNavigator.isScreenAllowed(Screen.Admin, Role.Supervisor))
    }

    @Test
    fun `operator cannot access admin screen`() {
        assertFalse(AppNavigator.isScreenAllowed(Screen.Admin, Role.Operator))
    }

