import com.eaglepoint.task136.shared.services.ValidationService
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.emptyFlow
import kotlinx.coroutines.test.runTest
import kotlinx.datetime.Clock
import kotlinx.datetime.Instant
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertNotNull
import kotlin.test.assertTrue

class InvoicePersistenceTest {
    private val notificationGateway = object : NotificationGateway {
        override suspend fun scheduleInvoiceReady(invoiceId: String, total: Double) = Unit
        override suspend fun scheduleMeetingNotification(meetingId: String, message: String) = Unit
    }

    private val receiptGateway = object : ReceiptGateway {
        override suspend fun shareReceipt(invoiceId: String, customerName: String, lineItems: List<ReceiptLineItem>, total: Double) = Unit
    }

    private val testClock = object : Clock {
        override fun now(): Instant = Instant.parse("2026-03-30T10:00:00Z")
    }

    private val fakeCartDao = object : CartDao {
        override suspend fun upsert(item: CartItemEntity) = Unit
        override suspend fun update(item: CartItemEntity) = Unit
        override suspend fun getByUser(userId: String) = emptyList<CartItemEntity>()
        override fun observeByUser(userId: String): Flow<List<CartItemEntity>> = emptyFlow()
        override suspend fun getById(id: String): CartItemEntity? = null
        override suspend fun getByIdForUser(id: String, userId: String): CartItemEntity? = null
        override suspend fun deleteById(id: String) = Unit
        override suspend fun deleteByIdForUser(id: String, userId: String) = Unit
        override suspend fun clearForUser(userId: String) = Unit
        override suspend fun upsertAll(items: List<CartItemEntity>) = Unit
    }

    private val fakeDeviceBindingDao = object : DeviceBindingDao {
        override suspend fun upsert(binding: DeviceBindingEntity) = Unit
        override suspend fun getByUserId(userId: String) = emptyList<DeviceBindingEntity>()
        override suspend fun countByUserId(userId: String) = 0
        override suspend fun deleteAllForUser(userId: String) = Unit
        override suspend fun findByUserAndDevice(userId: String, fingerprint: String): DeviceBindingEntity? =
            DeviceBindingEntity(id = "test", userId = userId, deviceFingerprint = fingerprint, boundAt = 0L)
    }

    private val storedInvoices = mutableMapOf<String, InvoiceEntity>()

    private val fakeInvoiceDao = object : InvoiceDao {
        override suspend fun upsert(invoice: InvoiceEntity) {
            storedInvoices[invoice.id] = invoice
        }
        override suspend fun getByOwner(ownerId: String) = storedInvoices.values.filter { it.ownerId == ownerId }
        override suspend fun getById(id: String) = storedInvoices[id]
        override suspend fun getRecent(limit: Int) = storedInvoices.values.toList().take(limit)
    }

    private fun createVm(): OrderFinanceViewModel {
        storedInvoices.clear()
        return OrderFinanceViewModel(
            abac = AbacPolicyEvaluator(),
            permissionEvaluator = PermissionEvaluator(defaultRules()),
            validationService = ValidationService(testClock),
            deviceBindingService = DeviceBindingService(fakeDeviceBindingDao, testClock),
            cartDao = fakeCartDao,
            invoiceDao = fakeInvoiceDao,
            notificationGateway = notificationGateway,
            receiptGateway = receiptGateway,
        )
    }

    @Test
    fun `invoice persists and can be reloaded from Room`() = runTest {
        val vm = createVm()
        // Add item and generate invoice
        vm.addDemoItem(Role.Admin, "admin")
        delay(50)
        vm.generateInvoice(Role.Admin, "admin")
        delay(200)

        val invoiceId = vm.state.value.invoices.firstOrNull()?.id
        assertNotNull(invoiceId, "Invoice should have been generated")

        // Simulate fresh VM by creating a new one
        val freshVm = createVm()
        freshVm.loadInvoiceById(invoiceId, Role.Admin, "admin")
        delay(200)

        val loaded = freshVm.state.value.invoices.firstOrNull { it.id == invoiceId }
        assertNotNull(loaded, "Invoice should be loadable from persistence")
        assertTrue(loaded.subtotal > 0)
    }

    @Test
    fun `invoice detail loads from persistence not memory`() = runTest {
        // Pre-populate a stored invoice
        storedInvoices["inv-test"] = InvoiceEntity(
            id = "inv-test",
            subtotal = 100.0,
            tax = 12.0,
            total = 112.0,
            orderId = "ord-test",
            ownerId = "admin",
            actorId = "admin",
            createdAt = 0L,
        )

        val vm = createVm()
        vm.loadInvoiceById("inv-test", Role.Admin, "admin")
        delay(200)

        val loaded = vm.state.value.invoices.firstOrNull { it.id == "inv-test" }
        assertNotNull(loaded)
        assertEquals(100.0, loaded.subtotal)
        assertEquals(112.0, loaded.total)
    }

    @Test
    fun `refund targets specific invoice not latest`() = runTest {
        // Set up two invoices
        storedInvoices["inv-1"] = InvoiceEntity(
            id = "inv-1", subtotal = 50.0, tax = 6.0, total = 56.0,
            orderId = null, ownerId = "admin", actorId = "admin", createdAt = 0L,
        )
        storedInvoices["inv-2"] = InvoiceEntity(
            id = "inv-2", subtotal = 100.0, tax = 12.0, total = 112.0,
            orderId = null, ownerId = "admin", actorId = "admin", createdAt = 1L,
        )

        val vm = createVm()
        // Load inv-1 specifically
        vm.loadInvoiceById("inv-1", Role.Admin, "admin")
        delay(200)

        // Attempt refund on inv-1 - will fail because no linked order, but that's fine
        // What we verify is it targets inv-1 not inv-2
        vm.refundInvoice("inv-1", Role.Admin, "admin")
        delay(200)

        // The note should reference the specific invoice
        val note = vm.state.value.note.orEmpty()
        assertTrue(note.contains("inv-1") || note.contains("Refund requires"), "Refund should target specific invoice inv-1, got: $note")
    }

    @Test
    fun `process loss scenario - new VM can still load invoice`() = runTest {
        storedInvoices["inv-persisted"] = InvoiceEntity(
            id = "inv-persisted", subtotal = 75.0, tax = 9.0, total = 84.0,
            orderId = "ord-99", ownerId = "operator", actorId = "operator", createdAt = 0L,
        )

        // Fresh VM with no prior state
        val freshVm = createVm()
        assertTrue(freshVm.state.value.invoices.isEmpty(), "Fresh VM should have no in-memory invoices")

        freshVm.loadInvoiceById("inv-persisted", Role.Operator, "operator")
        delay(200)

        val loaded = freshVm.state.value.invoices.firstOrNull { it.id == "inv-persisted" }
        assertNotNull(loaded, "Should be able to load persisted invoice even on fresh VM")
        assertEquals(75.0, loaded.subtotal)
    }
}
"}

