8	    actual suspend fun downsample(bytes: ByteArray, maxWidth: Int, maxHeight: Int): ImageBitmap? {
9	        val bounds = BitmapFactory.Options().apply { inJustDecodeBounds = true }
10	        BitmapFactory.decodeByteArray(bytes, 0, bytes.size, bounds)
11	
12	        val sample = calculateInSampleSize(bounds.outWidth, bounds.outHeight, maxWidth, maxHeight)
13	        val options = BitmapFactory.Options().apply { inSampleSize = sample }
14	        val bitmap = BitmapFactory.decodeByteArray(bytes, 0, bytes.size, options) ?: return null
15	        return bitmap.asImageBitmap()
16	    }
17	
18	    private fun calculateInSampleSize(width: Int, height: Int, reqWidth: Int, reqHeight: Int): Int {
19	        var inSampleSize = 1
20	        var halfHeight = height / 2
21	        var halfWidth = width / 2
22	
23	        while (halfHeight / inSampleSize >= reqHeight && halfWidth / inSampleSize >= reqWidth) {
24	            inSampleSize *= 2
25	        }
26	        return inSampleSize.coerceAtLeast(1)
27	    }
