        override suspend fun getByIdForActor(orderId: String, actorId: String) = storedOrders[orderId]?.takeIf { it.userId == actorId }
        override suspend fun getByIdForOwnerOrDelegate(orderId: String, ownerId: String, delegateOwnerId: String): OrderEntity? = null
        override fun observeById(orderId: String): Flow<OrderEntity?> = emptyFlow()
        override suspend fun getActiveByResource(resourceId: String) = emptyList<OrderEntity>()
        override suspend fun deleteById(orderId: String) = Unit
        override suspend fun page(limit: Int) = emptyList<OrderEntity>()
        override suspend fun getExpiredPendingOrders(nowMillis: Long) = emptyList<OrderEntity>()
        override suspend fun sumGrossByDateRange(fromMillis: Long, toMillis: Long) = 0.0
        override suspend fun sumRefundsByDateRange(fromMillis: Long, toMillis: Long) = 0.0
    }

    private fun createFinanceVm(): OrderFinanceViewModel {
        storedInvoices.clear()
        storedOrders.clear()
        return OrderFinanceViewModel(
            abac = AbacPolicyEvaluator(),
            permissionEvaluator = PermissionEvaluator(defaultRules()),
            validationService = ValidationService(testClock),
            deviceBindingService = DeviceBindingService(fakeDeviceBindingDao, testClock),
            cartDao = fakeCartDao,
            invoiceDao = fakeInvoiceDao,
            orderDao = orderDaoWithStorage,
            notificationGateway = fakeNotificationGateway,
            receiptGateway = receiptGateway,
            clock = testClock,
        )
    }

    @Test
    fun `invoice stores canonical tax regardless of role`() = runTest {
        val vm = createFinanceVm()
        // Add item as Operator (non-admin, cannot see tax in display)
        vm.addCartItem(Role.Operator, "operator", resourceId = "res-1", label = "Test", quantity = 1, unitPrice = 100.0)
        delay(50)
        vm.generateInvoice(Role.Operator, "operator")
        delay(200)

        val persisted = storedInvoices.values.firstOrNull()
        assertNotNull(persisted, "Invoice should be persisted")
        // Tax should be stored canonically (12%), not zeroed
        assertEquals(12.0, persisted.tax, "Tax should be stored as canonical 12%")
        assertEquals(112.0, persisted.total, "Total should include canonical tax")
    }

    @Test
    fun `non-admin sees masked tax in draft but canonical is persisted`() = runTest {
        val vm = createFinanceVm()
        vm.addCartItem(Role.Operator, "operator", resourceId = "res-1", label = "Test", quantity = 1, unitPrice = 50.0)
        delay(50)
        vm.generateInvoice(Role.Operator, "operator")
        delay(200)

        // In-memory draft for non-admin should mask tax
        val draft = vm.state.value.invoices.firstOrNull()
        assertNotNull(draft)
        assertEquals(0.0, draft.tax, "Non-admin draft should show masked (zero) tax")
        // But persisted entity has canonical tax
        val entity = storedInvoices.values.firstOrNull()
        assertNotNull(entity)
        assertEquals(6.0, entity.tax, "Stored tax should be canonical")
    }

    // ── D. Invoice linked to real order ──

    @Test
    fun `invoice links to real persisted order`() = runTest {
        val vm = createFinanceVm()
        vm.addCartItem(Role.Admin, "admin", resourceId = "res-1", label = "Test", quantity = 1, unitPrice = 20.0)
        delay(50)
        vm.generateInvoice(Role.Admin, "admin")
        delay(200)

        val invoice = storedInvoices.values.firstOrNull()
        assertNotNull(invoice)
        val orderId = invoice.orderId
        assertNotNull(orderId, "Invoice must have a linked order ID")
        assertTrue(orderId.startsWith("ord-"), "Order ID must be a real order reference, got: $orderId")

        // Verify the order is actually persisted
        val order = storedOrders[orderId]
        assertNotNull(order, "Linked order must exist in persistence")
    }

    @Test
    fun `refund fails for invoice with missing order in persistence`() = runTest {
        val vm = createFinanceVm()
        // Insert invoice with an orderId that doesn't map to a stored order
        storedInvoices["inv-orphan"] = InvoiceEntity(
            id = "inv-orphan", subtotal = 50.0, tax = 6.0, total = 56.0,
            orderId = "ord-nonexistent", ownerId = "admin", actorId = "admin", createdAt = 0L,
        )
        vm.refundInvoice("inv-orphan", Role.Admin, "admin")
        delay(200)
        val note = vm.state.value.note.orEmpty()
        assertTrue(note.contains("Refund") && (note.contains("failed") || note.contains("transition")),
            "Refund should fail for invoice with invalid order link, got: $note")
    }

    // ── J. Order reminder scheduling ──

    @Test
    fun `order reminder gateway interface exists`() {
        // Verify the scheduleOrderReminder method is callable
        var called = false
        val gw = object : NotificationGateway {
            override suspend fun scheduleInvoiceReady(invoiceId: String, total: Double) = Unit
            override suspend fun scheduleMeetingNotification(meetingId: String, message: String) = Unit
            override suspend fun scheduleOrderReminder(orderId: String, message: String) { called = true }
        }
        runTest {
            gw.scheduleOrderReminder("ord-1", "test")
            assertTrue(called)
        }
    }
}
